#[async_trait]
impl<R: BackupCodeProjectionRepository> BackupCodeEventHandler for BackupCodeProjector<R> {

    async fn on_created(&self, event: BackupCodeCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = BackupCodeProjection::new(
            event.id,
            event.user_id,
            event.batch_id,
            event.code_hash,
            event.code_index,
            event.is_used,
            event.used_at,
            event.used_ip,
            event.used_user_agent,
            event.expires_at,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: BackupCodeUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.batch_id = event.batch_id;
            projection.code_hash = event.code_hash;
            projection.code_index = event.code_index;
            projection.is_used = event.is_used;
            projection.used_at = event.used_at;
            projection.used_ip = event.used_ip;
            projection.used_user_agent = event.used_user_agent;
            projection.expires_at = event.expires_at;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: BackupCodeDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

